//vip.opstream15.com/20221205/29372_26f580cb/index.m3u8"}]}],"time":"58 phút","description":"<p>Trong chương trình hài độc thoại đặc biệt do chính ông đạo diễn, Patton bàn về những hiểm nguy của lão hóa, kế hoạch đổ bể vào đợt giãn cách và ngày vợ ông biến thành Valkyrie.</p>","tmdb":{"type":"movie","id":"1004772","season":null,"vote_average":6,"vote_count":20},"modified":"2022-12-14T01:40:02.000Z"},{"id":"632b1df5decb16e375b0cf6f","_id":"632b1df5decb16e375b0cf6f","title":"Ngư Yêu","origin_name":"THE LEGEND OF AQUAWITCH","slug":"ngu-yeu","year":2022,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a222fe0fc277084dfd23d","name":"Cổ Trang","slug":"co-trang"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"},{"id":"620f84d291fa4af90ab6b3f4","name":"Bí ẩn","slug":"bi-an"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"ngu-yeu-2022","link_embed":"https://vip.opstream16.com/share/0f3cb4cc8c7d6da35362e70ba50cf923","link_m3u8":"https://vip.opstream16.com/20220921/22597_ce3e1e0b/index.m3u8"}]}],"time":"82 Phút","description":"<p>Đã có rất nhiều tin đồn. Gần đến tết trung thu, theo phong tục, Thái tử sẽ để tang người mẹ đã khuất của mình bên dòng sông trong Vườn thượng uyển. Quách Trưởng Chi lo lắng cho sự an toàn của Thái tử và ra lệnh cho ra lệnh cho Đại Lý Tự giải quyết vụ việc càng sớm càng tốt. Đại Lí Tự Chính Tiết Dương cùng với Đinh Nha Nhi liên thủ để cùng tìm ra hung thủ. Trong quá trình điều tra phát hiện ra ở dưới sông có một quái thú khổng lồ ăn thịt người được người ta nuôi, mà người nuôi cá quái thú lại là con quỷ võ công cao cường biến hóa tài tình. Vì một trận động đất, con quỷ cá đã thoát ra khỏi lồng khiến thảm kịch xảy ra. Mục đích của hắn là muốn quái thú cá ăn thịt Thái tử. Liên quan đến việc kế vị ngai vàng, Tiết Dương bị vu oan và bị tống vào nhà giam. May mắn thay, Quách Trưởng Chi đã giúp và bí mật cử người đến giúp đỡ. Vào đêm Trung thu trên sông Khúc, một trận chiến của người và cá đã ngăn chặn âm mưu giết Thái tử.</p>","tmdb":{"type":"movie","id":"1017159","season":null,"vote_average":8,"vote_count":1},"modified":"2022-09-21T17:34:27.000Z"},{"id":"632b38f7decb16e375b1a0d8","_id":"632b38f7decb16e375b1a0d8","title":"Jujutsu Kaisen 0: Chú Thuật Hồi Chiến","origin_name":"Jujutsu Kaisen 0: The Movie","slug":"jujutsu-kaisen-0-chu-thuat-hoi-chien","year":2021,"type":"hoathinh","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"}],"country":[{"id":"620a2307e0fc277084dfd726","name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":true,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Vietsub #1","server_data":[{"name":"Full","slug":"full","filename":"Vietsub - BDRIP Jujutsu Kaisen 0 - The Movie 2021","link_embed":"https://vip.opstream16.com/share/745b601f1064f3e9a35cf1747b740e5e","link_m3u8":"https://vip.opstream16.com/20220921/22596_53fb59ed/index.m3u8"}]}],"time":"105 Phút","description":"<p>Những bất hạnh bạo lực thường xuyên xảy ra xung quanh Yuuta Okkotsu, 16 tuổi, một nạn nhân nhút nhát của nạn bắt nạt ở trường trung học. Yuuta bị đeo một lời nguyền quái dị, một sức mạnh có thể gây ra sự trả thù tàn bạo chống lại những kẻ bắt nạt mình. Rika Orimoto, lời nguyền của Yuuta, là cái bóng từ thời thơ ấu đầy bi kịch của anh và là mối đe dọa có thể gây chết người cho bất cứ ai dám sai anh ta.Tình huống độc đáo của Yuuta thu hút sự chú ý của Satoru Gojou, một pháp sư quyền năng đang giảng dạy tại trường Trung học Jujutsu Tokyo. Gojou nhìn thấy tiềm năng to lớn ở Yuuta, và ông hy vọng sẽ giúp cậu bé chuyển gánh nặng chết chóc của mình thành một lực lượng tốt. Tuy nhiên, Yuuta phải vật lộn để tìm được vị trí của mình trong số những người bạn học tài năng của mình: Toge Inumaki bị câm có chọn lọc, chuyên gia vũ khí Maki Zenin và Panda.Yuuta sử dụng Rika một cách vụng về trong các nhiệm vụ với các học sinh năm nhất khác, nhưng hậu quả khủng khiếp của màn thể hiện sức mạnh khủng khiếp của Rika đã thu hút sự quan tâm của người sử dụng lời nguyền tính toán Suguru Getou. Khi Getou cố gắng yêu cầu sức mạnh của Rika và sử dụng nó để loại bỏ tất cả những người không sử dụng thuật thuật trên thế giới, Yuuta chiến đấu cùng với bạn bè của mình để ngăn chặn âm mưu diệt chủng.</p>","tmdb":{"type":null,"id":"","season":null,"vote_average":0,"vote_count":0},"modified":"2022-09-21T17:34:11.000Z"},{"id":"632b4bbcdecb16e375b204a8","_id":"632b4bbcdecb16e375b204a8","title":"Đám Cưới","origin_name":"Wedding","slug":"dam-cuoi","year":2005,"type":"series","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"}],"country":[{"id":"620a2300e0fc277084dfd6d2","name":"Hàn Quốc","slug":"han-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (18/18)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Vietsub #1","server_data":[{"name":"1","slug":"1","filename":"dam-cuoi--eps-tap-1","link_embed":"https://vip.opstream16.com/share/e0132a0ce408b645b9636d5ab4707f7b","link_m3u8":"https://vip.opstream16.com/20220921/22595_31933907/index.m3u8"},{"name":"2","slug":"2","filename":"dam-cuoi--eps-tap-2","link_embed":"https://vip.opstream16.com/share/8e6a4217e8a7391fdc7e89a120fe5d86","link_m3u8":"https://vip.opstream16.com/20220921/22578_ab6a1d98/index.m3u8"},{"name":"3","slug":"3","filename":"dam-cuoi--eps-tap-3","link_embed":"https://vip.opstream16.com/share/599b61